queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?benefitname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBenefits ?child ; p:hasCredit_Cards ?parent . } GROUP BY ?child }
  ?child p:benefitName ?benefitname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Credit_Cards } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?benefitname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBenefits ?child ; p:hasCredit_Cards ?parent . } GROUP BY ?child }
  ?child p:benefitName ?benefitname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Credit_Cards } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?cardnumber ?benefitname WHERE {
  ?credit_card_benefits a :Credit_Card_Benefits .
  ?benefits a :Benefits .
  ?credit_card_benefits p:hasBenefits ?benefits .
  ?credit_cards a :Credit_Cards .
  ?credit_card_benefits p:hasCredit_Cards ?credit_cards .
  ?credit_cards p:cardNumber ?cardnumber .
  ?benefits p:benefitName ?benefitname .
} }
}
